then.script:
var response = mc.getPayloadJSON();

// Get stored properties
var initPayload = mc.getProperty("initPayload");
var policyId = mc.getProperty("policyId");

// Ensure initPayload is parsed if stored as string
if (typeof initPayload === "string") {
    initPayload = JSON.parse(initPayload);
}

// Ensure data object exists (your existing logic)
if (response && response.data) {

    var payload = response.data;

    // Remove _id if present
    if (payload._id) {
        delete payload._id;
    }

    var result = {};


    if (payload.policyStatusCode === "CANCELLED") {

        if (payload.policyCancellationType === 
            (initPayload.policyEvent ? initPayload.policyEvent.eventReasonCode : null)) {

            var timestamp = new Date();
            var formattedTimestamp =
                timestamp.getFullYear().toString() +
                ("0" + (timestamp.getMonth() + 1)).slice(-2) +
                ("0" + timestamp.getDate()).slice(-2) +
                ("0" + timestamp.getHours()).slice(-2) +
                ("0" + timestamp.getMinutes()).slice(-2) +
                ("0" + timestamp.getSeconds()).slice(-2) +
                ("00" + timestamp.getMilliseconds()).slice(-3);

            var totalPremium = payload.pricing && payload.pricing.totalPremium
                ? Number(payload.pricing.totalPremium)
                : 0;

            result = {
                policyNumber: policyId || "",
                quoteId: payload.quote ? payload.quote.quoteId || "" : "",
                reinstatementId: "RES-" + formattedTimestamp,
                policyStatusCode: "REINSTATEMENT_REQUESTED",
                policyEvent: {
                    eventTypeCode: "REINSTATEMENT",
                    eventDate: initPayload.policyEvent ? initPayload.policyEvent.eventDate || "" : "",
                    eventReasonCode: initPayload.policyEvent ? initPayload.policyEvent.eventReasonCode || "" : "",
                    eventReasonDescription: initPayload.policyEvent ? initPayload.policyEvent.eventReasonDescription || "" : ""
                },
                assessmentTypeCode: "REINSTATEMENT_EVALUATION",
                assessmentStatusCode: "PENDING",
                outstandingAmount: {
                    amountValue: totalPremium + (totalPremium * 0.02),
                    currencyCode: "USD"
                },
                reinstateTermStartDate: initPayload.reinstateTermStartDate || null,
                reinstateTermEndDate: initPayload.reinstateTermEndDate || null,
                status: "SUCCESS",
                message: "Reinstatement request submitted successfully"
            };

        } else {

            result = {
                policyNumber: policyId || "",
                quoteId: payload.quote ? payload.quote.quoteId || "" : "",
                policyStatusCode: payload.policyStatusCode || "",
                status: "FAILED",
                message: "Reinstatement is not allowed. Policy cancellation type or event reason is not eligible for reinstatement."
            };
        }

    } else {

        result = {
            policyNumber: policyId || "",
            quoteId: payload.quote ? payload.quote.quoteId || "" : "",
            policyStatusCode: payload.policyStatusCode,
            status: "FAILED",
            message: "Reinstatement request cannot be processed because the policy is not in CANCELLED status."
        };
    }

    // Set final payload
   mc.setPayloadJSON(result);

// Store the same object as a property
mc.setProperty("response", JSON.stringify(result));
}

// Get payload as string
var payloadStr = mc.getPayloadJSON();
// If payload is already an object, convert to string first
if (typeof payloadStr !== "string") {
payloadStr = JSON.stringify(payloadStr);
}
// Parse string to JSON object
var payload = JSON.parse(payloadStr);
// Remove unwanted fields
delete payload.status;
delete payload.message;
// Set updated payload back
mc.setPayloadJSON(payload);

// Get response property (stored as String)
var responseStr = mc.getProperty("response");
// Parse string to JSON object
var response = {};
if (responseStr != null) {
response = JSON.parse(responseStr);
}
// Construct new payload
var newPayload = {
policyStatusCode: response.policyStatusCode || "",
reinstatements: [
{
reinstatementId: response.reinstatementId || ""
}
]
};
// Set as new payload
mc.setPayloadJSON(newPayload);
